import java.util.Scanner;
import java.util.Arrays;

public class SecureBuffer {

    public static void main(String[] args) {
        Scanner scanner = new Scanner(System.in);

        System.out.print("Enter your name: ");
        String name = scanner.next();

        // Validate input size before copying to buffer
        if (name.length() > 10) {
            System.out.println("Input size exceeds buffer size limit. Please enter a shorter name.");
            return;
        }

        byte[] buffer = new byte[10];
        Arrays.fill(buffer, (byte) 0); // Fill buffer with zeros for safety
        System.arraycopy(name.getBytes(), 0, buffer, 0, name.length());

        System.out.println("Buffer content: " + new String(buffer));

        scanner.close();
    }
}

### Explanation:
취약유형: Buffer Overflow
